import json

# Load the dataset list from the previous response
datasets_json = """[
  {
    "id": "miso_lmp_day_ahead_hourly",
    "name": "MISO LMP Day Ahead Hourly",
    "description": "Day Ahead LMP in hourly intervals as reported by MISO.\\n\\nThis dataset includes the location types:\\n- *Gennode*\\n-  *Hub*\\n-  *Interface*\\n-  *Loadzone*"
  },
  {
    "id": "miso_lmp_day_ahead_hourly_ex_ante",
    "name": "MISO LMP Day Ahead Hourly Ex Ante",
    "description": "Day-ahead, hourly, Ex-Ante, LMPs publishing by MISO prior to the operating day. Ex-Ante LMPs are published in the early afternoon of the day prior to the market day, several hours before the Ex-Post day-ahead LMPs. The Ex-Ante LMPs are derived from the day-aead market clearing process.\\n\\nSee MISO's *BPM 002 - Energy and Operating Reserves* for additional discussion."
  },
  {
    "id": "miso_lmp_day_ahead_hourly_ex_post",
    "name": "MISO LMP Day Ahead Hourly Ex Post",
    "description": "Day-ahead, hourly, Ex-Post, LMPs publishing by MISO prior to the operating day. Ex-Post LMPs are published in the late afternoon or early evening of the day prior to the market day, several hours after the Ex-Ante day-ahead LMPs.\\n\\nSee MISO's *BPM 002 - Energy and Operating Reserves* for additional discussion."
  },
  {
    "id": "miso_lmp_real_time_5_min",
    "name": "MISO LMP Real Time 5 Min",
    "description": "Preliminary real-time ExPost LMP prelim in 5 minute intervals as reported by MISO.\\n\\nThis dataset includes the location types:\\n- *Gennode*\\n-  *Hub*\\n-  *Interface*\\n-  *Loadzone*"
  },
  {
    "id": "miso_lmp_real_time_5_min_ex_ante",
    "name": "MISO LMP Real Time 5 Min Ex Ante",
    "description": "Ex-Ante, real-time, five-minute, LMPs in MISO. These are the LMPs calculated via the *SCED* program on a 5-minute basis in MISO, which produces the economic dispatch. Ex-Ante LMPs in real-time are for informational purposes only. \\n\\nEx-Post LMPs may differ from Ex-Ante LMPs depending on fast start and emergency operations resources.\\n\\nSee MISO's *BPM 002 - Energy and Operating Reserves* for additional discussion."
  },
  {
    "id": "miso_lmp_real_time_5_min_ex_post_final",
    "name": "MISO LMP Real Time 5 Min Ex Post Final",
    "description": "Final Ex Post real-time five-minute LMPs in MISO. These are the LMPs calculated after the publication of Preliminary real-time LMPs by MISO following the approval of each Unit Dispatch System (UDS) case.\\n\\nThe Final values are not available immediately in real-time, but calculated via an offline process throughout the operating day and into the next day.\\n\\nSee MISO's *BPM 002 - Energy and Operating Reserves* for additional discussion."
  },
  {
    "id": "miso_lmp_real_time_5_min_ex_post_prelim",
    "name": "MISO LMP Real Time 5 Min Ex Post Prelim",
    "description": "Preliminary Ex-Post real-time five-minute LMPs in MISO. These are the LMPs calculated automatically in real-time by MISO following the approval of each Unit Dispatch System (UDS) case by the *SCED-Pricing* program.\\n\\nEx-Post LMPs may differ from Ex-Ante LMPs depending on fast start and emergency operations resources.\\n\\nSee MISO's *BPM 002 - Energy and Operating Reserves* for additional discussion."
  },
  {
    "id": "miso_lmp_real_time_5_min_final",
    "name": "MISO LMP Real Time 5 Min Final",
    "description": "Final Five-minute real-time ExPost LMPs for each Pnode in MISO, includes energy, loss, and\\ncongestion components. \\n\\nThis data updates on Mondays and is provided by MISO on a weekly basis for the week prior to the previous week. \\n\\nThis dataset includes the location types:\\n- *Gennode*\\n-  *Hub*\\n-  *Interface*\\n-  *Loadzone*\\n\\nFor more information see the MISO Pricing Reports Guide (PDF): [https://misodocs.blob.core.windows.net/marketreports/Real-Time Preliminary Market LMPs_MISO Pricing Reports Readers Guide.pdf](https://misodocs.blob.core.windows.net/marketreports/Real-Time%20Preliminary%20Market%20LMPs_MISO%20Pricing%20Reports%20Readers%20Guide.pdf)"
  },
  {
    "id": "miso_lmp_real_time_hourly_ex_post_final",
    "name": "MISO LMP Real Time Hourly Ex Post Final",
    "description": "Final, hourly, real-time, Ex Post, LMPs from MISO. MISO integrates the real-time Ex Post LMP over all dispatch intervals in a market hour in order to produce the hourly value. MISO's real-time market is settled on the hourly Ex post LMPs.\\n\\nThe Final values are not available immediately in real-time, but calculated via an offline process throughout the operating day and into the next day.\\n\\nSee MISO's *BPM 002 - Energy and Operating Reserves* for additional discussion."
  },
  {
    "id": "miso_lmp_real_time_hourly_ex_post_prelim",
    "name": "MISO LMP Real Time Hourly Ex Post Prelim",
    "description": "Preliminary, hourly, real-time, Ex Post LMPs from MISO. MISO integrates the real-time Ex Post LMP over all dispatch intervals in a market hour in order to produce the hourly value. MISO's real-time market is ultimately settled on the hourly Ex post LMPs, but this dataset is the Preliminary values which are calculated in real time, directly following the market hour. \\n\\nSee MISO's *BPM 002 - Energy and Operating Reserves* for additional discussion."
  },
  {
    "id": "miso_lmp_real_time_hourly_final",
    "name": "MISO LMP Real Time Hourly Final",
    "description": "Final hourly real-time LMPs for each Pnode in MISO, includes energy, loss, and\\ncongestion components. It takes 3-5 days for MISO to finalize LMPs, so these values\\nwill be delayed by several days from the market date. This dataset includes the location types:\\n- *Gennode*\\n-  *Hub*\\n-  *Interface*\\n-  *Loadzone*\\n\\nFor more information see the MISO Pricing Reports Guide (PDF): [https://misodocs.blob.core.windows.net/marketreports/Real-Time Preliminary Market LMPs_MISO Pricing Reports Readers Guide.pdf](https://misodocs.blob.core.windows.net/marketreports/Real-Time%20Preliminary%20Market%20LMPs_MISO%20Pricing%20Reports%20Readers%20Guide.pdf)"
  },
  {
    "id": "miso_lmp_real_time_hourly_prelim",
    "name": "MISO LMP Real Time Hourly Prelim",
    "description": "Preliminary hourly real-time LMPs for each Pnode in MISO, includes energy, loss,\\nand congestion components. It takes 3-5 days for MISO to finalize LMPs, these are\\nthe interim values before final LMPs are published. This dataset includes the location types:\\n- *Gennode*\\n-  *Hub*\\n-  *Interface*\\n-  *Loadzone*\\n\\nFor more information see the MISO Pricing Reports Guide (PDF): [https://misodocs.blob.core.windows.net/marketreports/Real-Time Preliminary Market LMPs_MISO Pricing Reports Readers Guide.pdf](https://misodocs.blob.core.windows.net/marketreports/Real-Time%20Preliminary%20Market%20LMPs_MISO%20Pricing%20Reports%20Readers%20Guide.pdf)"
  }
]"""

datasets = json.loads(datasets_json)
print("MISO LMP datasets that might contain hub data:")
for dataset in datasets:
    print(f"ID: {dataset['id']}")
    print(f"Name: {dataset['name']}")
    print(f"Description: {dataset['description'][:100]}...")
    print("-" * 80)

